import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './AdminLogin.css';

const AdminLogin = ({ language }) => {
  const [institutionId, setInstitutionId] = useState('');
  const [accessKey, setAccessKey] = useState('');
  const navigate = useNavigate();

  const content = {
    en: {
      title: 'Admin Portal',
      subtitle: 'Institutional Administrator Access',
      institutionLabel: 'Institution ID',
      accessKeyLabel: 'Access Key',
      loginButton: 'Login',
      privacyNotice: '🔒 Student identities are never visible to administrators. All data is anonymized.'
    },
    hi: {
      title: 'व्यवस्थापक पोर्टल',
      subtitle: 'संस्थागत प्रशासक पहुंच',
      institutionLabel: 'संस्था आईडी',
      accessKeyLabel: 'एक्सेस कुंजी',
      loginButton: 'लॉगिन',
      privacyNotice: '🔒 छात्र पहचान प्रशासकों को कभी दिखाई नहीं देती। सभी डेटा गुमनाम है।'
    }
  };

  const text = content[language] || content.en;

  const handleLogin = (e) => {
    e.preventDefault();
    // In real implementation, authenticate with Cognito
    navigate('/admin/dashboard');
  };

  return (
    <div className="admin-login-page">
      <div className="admin-login-container">
        <h1>{text.title}</h1>
        <p className="subtitle">{text.subtitle}</p>

        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label>{text.institutionLabel}</label>
            <input
              type="text"
              value={institutionId}
              onChange={(e) => setInstitutionId(e.target.value)}
              required
            />
          </div>

          <div className="form-group">
            <label>{text.accessKeyLabel}</label>
            <input
              type="password"
              value={accessKey}
              onChange={(e) => setAccessKey(e.target.value)}
              required
            />
          </div>

          <button type="submit" className="login-button">
            {text.loginButton}
          </button>
        </form>

        <div className="privacy-notice">
          {text.privacyNotice}
        </div>
      </div>
    </div>
  );
};

export default AdminLogin;
